#!/usr/bin/env bash
# Generated by bun-bench Harbor export adapter. Oracle reference solution.
# Overwrites the starter source under /app with the bun-bench reference.
set -euo pipefail

mkdir -p /app/src
cat > /app/src/server.ts <<'BUN_BENCH_SOLUTION_EOF'
import { Database } from "bun:sqlite";
import { mkdirSync } from "node:fs";
import { dirname } from "node:path";

const port = Number(Bun.env.PORT ?? 3000);
const dbPath = Bun.env.DATABASE_PATH ?? "./data/app.db";

if (dbPath !== ":memory:") {
  mkdirSync(dirname(dbPath), { recursive: true });
}

const db = new Database(dbPath);
db.exec("PRAGMA journal_mode = WAL;");

// The ordered migration list. Each migration runs exactly once over the
// lifetime of the database, recorded in schema_migrations by name.
type Migration = { name: string; up: () => void };

const migrations: Migration[] = [
  {
    name: "create_users",
    up: () => {
      db.exec(`CREATE TABLE users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL
      );`);
    },
  },
  {
    name: "add_users_email",
    up: () => {
      // Guarded by schema_migrations: this runs only on the first boot. A naive
      // unconditional ALTER would crash on the second boot ("duplicate column").
      db.exec("ALTER TABLE users ADD COLUMN email TEXT;");
    },
  },
  {
    name: "index_users_email",
    up: () => {
      db.exec("CREATE INDEX idx_users_email ON users (email);");
    },
  },
];

function runMigrations(): void {
  db.exec(`CREATE TABLE IF NOT EXISTS schema_migrations (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL UNIQUE,
    applied_at TEXT NOT NULL DEFAULT (datetime('now'))
  );`);

  const isApplied = db.query<{ name: string }, [string]>(
    "SELECT name FROM schema_migrations WHERE name = ?",
  );
  const record = db.query("INSERT INTO schema_migrations (name) VALUES (?)");

  for (const migration of migrations) {
    if (isApplied.get(migration.name)) continue;
    const apply = db.transaction(() => {
      migration.up();
      record.run(migration.name);
    });
    apply();
  }
}

runMigrations();

type User = { id: number; name: string; email: string };

Bun.serve({
  port,
  async fetch(request) {
    const url = new URL(request.url);
    const segments = url.pathname.split("/").filter(Boolean);

    if (request.method === "GET" && url.pathname === "/schema/version") {
      const rows = db
        .query<{ name: string }, []>(
          "SELECT name FROM schema_migrations ORDER BY id ASC",
        )
        .all();
      const applied = rows.map((row) => row.name);
      return Response.json({ version: applied.length, applied }, { status: 200 });
    }

    if (request.method === "POST" && url.pathname === "/users") {
      let body: unknown;
      try {
        body = await request.json();
      } catch {
        return Response.json({ error: "invalid_json" }, { status: 400 });
      }
      const record = body as Record<string, unknown> | null;
      if (!record || typeof record.name !== "string" || typeof record.email !== "string") {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      const created = db
        .query<User, [string, string]>(
          "INSERT INTO users (name, email) VALUES (?, ?) RETURNING id, name, email",
        )
        .get(record.name, record.email)!;
      return Response.json(created, { status: 201 });
    }

    if (
      request.method === "GET" &&
      segments.length === 2 &&
      segments[0] === "users"
    ) {
      const id = Number(segments[1]);
      if (!Number.isInteger(id) || id <= 0) {
        return Response.json({ error: "not_found" }, { status: 404 });
      }
      const user = db
        .query<User, [number]>("SELECT id, name, email FROM users WHERE id = ?")
        .get(id);
      if (!user) return Response.json({ error: "not_found" }, { status: 404 });
      return Response.json(user, { status: 200 });
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`sqlite-migrations reference listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
